<?php namespace Database\Seeders; use App\Models\Role; use App\Models\Permission; use Illuminate\Database\Seeder; class RolesPermissionsSeeder extends Seeder { public function run(): void { $perms = [['sales.orders.create', 'sales', 'orders', 'create'],['sales.orders.approve', 'sales', 'orders', 'approve'],['sales.orders.override', 'sales', 'orders', 'override'],['accounts.authorize', 'accounts', 'invoices', 'authorize'],['inventory.stock.adjust', 'inventory', 'stock', 'adjust'],['kyc.approve', 'kyc', 'applications', 'approve'],['audit.view', 'audit', 'logs', 'view'],['users.manage', 'users', 'users', 'manage'],['reports.view', 'reports', 'reports', 'view']]; foreach ($perms as [$slug, $mod, $res, $act]) { Permission::firstOrCreate(['slug' => $slug], ['name' => ucfirst($slug), 'module' => $mod, 'resource' => $res, 'action' => $act]); } $superAdmin = Role::firstOrCreate(['slug' => 'super-admin'], ['name' => 'Super Admin', 'is_system' => true]); $superAdmin->permissions()->sync(Permission::all()->pluck('id')); } }
